/* ─── DATA FETCHING ─────────────────────────────────────────────── */
async function fetchSheet(sheetName) {
  const url = `${SHEETDB_URL}?sheet=${encodeURIComponent(sheetName)}`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Error leyendo hoja "${sheetName}" (${res.status})`);
  return res.json();
}

function useSheetData() {
  const [state, setState] = useState({ loading: true, error: null, data: null });

  const load = useCallback(async () => {
    setState((s) => ({ ...s, loading: true, error: null }));
    try {
      const [jugadores, inscripciones, torneosRows, categoriasRows, configRows, pagosRows] = await Promise.all([
        fetchSheet("jugadores"),
        fetchSheet("inscripciones"),
        fetchSheet("torneos"),
        fetchSheet("categorías"),
        fetchSheet("config"),
        fetchSheet("pagos"),
      ]);

      const torneos = {};
      torneosRows.forEach((t) => {
        const id = clean(t.torneo_id);
        if (!id) return;
        torneos[id] = {
          torneo_id: id,
          nombre: clean(t.nombre),
          sede: clean(t.sede),
          fecha: clean(t.fecha),
          inscripcion: num(t.inscripcion),
          estado: clean(t.estado).toLowerCase(),
        };
      });

      const config = {};
      configRows.forEach((r) => { config[clean(r.clave)] = clean(r.valor); });

      const insc = inscripciones.map((r) => ({
        dni: clean(r.dni),
        nombre: clean(r.nombre),
        torneo_id: clean(r.torneo_id),
        categoria: clean(r.categoria),
        catFacu: clean(r["cat Facu"]),
        pareja: clean(r.pareja),
        inscripto: isTrue(r.inscripto),
        pagado50: isTrue(r["pagado50%"]),
        pagado100: isTrue(r["pagado100%"]),
        metodoPago: clean(r.metodo_pago),
        botellas: num(r.botellas),
        botellasDeuda: num(r.botellas_deuda),
        resultado: clean(r.resultado),
        puntos: num(r.puntos),
      }));

      const pagos = pagosRows.map((r) => ({
        id: clean(r.id),
        dni: clean(r.dni_jugador),
        nombre: clean(r.nombre_jugador),
        monto: num(r.monto),
        nombreTransferencia: clean(r.nombre_transferencia),
        concepto: clean(r.concepto),
        estado: clean(r.estado).toLowerCase() || "pendiente",
        fecha: clean(r.fecha),
      }));

      const categorias = categoriasRows.map((r) => ({
        torneo_id: clean(r.torneo_id),
        categoria_id: clean(r.categoria_id),
        cupoTotal: num(r.cupo_total),
        inscriptos: num(r.inscriptos),
      }));

      setState({ loading: false, error: null, data: { jugadores, insc, torneos, categorias, config, pagos } });
    } catch (e) {
      setState({ loading: false, error: e.message || "Error desconocido", data: null });
    }
  }, []);

  useEffect(() => { load(); }, [load]);

  return { ...state, reload: load };
}

/* ─── DERIVED DATA ──────────────────────────────────────────────── */
function buildRanking(insc, categoriaFiltro) {
  const map = {};
  insc.forEach((row) => {
    if (!row.nombre || !row.puntos) return;
    if (categoriaFiltro && row.categoria.toUpperCase() !== categoriaFiltro.toUpperCase()) return;
    if (!map[row.nombre]) map[row.nombre] = { nombre: row.nombre, puntos: 0, detalle: [] };
    map[row.nombre].puntos += row.puntos;
    map[row.nombre].detalle.push({ resultado: row.resultado, categoria: row.categoria, puntos: row.puntos, torneo_id: row.torneo_id });
  });
  return Object.values(map).sort((a, b) => b.puntos - a.puntos);
}

function getCategorias(insc) {
  const set = new Set();
  insc.forEach((r) => { if (r.categoria) set.add(r.categoria.toUpperCase()); });
  const arr = Array.from(set);
  arr.sort((a, b) => {
    const ia = CATEGORIA_ORDEN.indexOf(a);
    const ib = CATEGORIA_ORDEN.indexOf(b);
    if (ia === -1 && ib === -1) return a.localeCompare(b);
    if (ia === -1) return 1;
    if (ib === -1) return -1;
    return ia - ib;
  });
  return arr;
}

function getJugadorByDni(insc, dni) {
  const rows = insc.filter((r) => r.dni && r.dni === dni && r.torneo_id);
  if (rows.length === 0) return null;
  return { dni, nombre: rows[0].nombre, filas: rows };
}

function calcularDeuda(filas, torneos, precioBotella) {
  let total = 0; const detalle = [];
  filas.forEach((t) => {
    const cfg = torneos[t.torneo_id];
    if (!cfg || !t.inscripto) return;
    if (!t.pagado50) { total += cfg.inscripcion / 2; detalle.push({ concepto: `${cfg.nombre} — 50% inscripción`, monto: cfg.inscripcion / 2 }); }
    else if (!t.pagado100) { total += cfg.inscripcion / 2; detalle.push({ concepto: `${cfg.nombre} — saldo inscripción`, monto: cfg.inscripcion / 2 }); }
    if (t.botellasDeuda > 0) { const m = t.botellasDeuda * precioBotella; total += m; detalle.push({ concepto: `${cfg.nombre} — ${t.botellasDeuda} botella(s)`, monto: m }); }
  });
  return { total, detalle };
}


/* ─── MODAL PAGO ────────────────────────────────────────────────── */
function ModalPago({ jugador, torneos, precioBotella, alias, onClose, onEnviar }) {
  const { total, detalle } = calcularDeuda(jugador.filas, torneos, precioBotella);
  const [monto, setMonto] = useState(String(total));
  const [nombre, setNombre] = useState("");
  const [concepto, setConcepto] = useState(detalle[0]?.concepto || "");
  const [enviado, setEnviado] = useState(false);
  const [enviando, setEnviando] = useState(false);
  const [err, setErr] = useState("");
  const ok = monto && nombre;

  const confirmar = async () => {
    if (!ok) return;
    setEnviando(true); setErr("");
    try {
      const body = {
        data: {
          id: String(Date.now()),
          dni_jugador: jugador.dni,
          nombre_jugador: jugador.nombre,
          monto: Number(monto),
          nombre_transferencia: nombre,
          concepto,
          estado: "pendiente",
          fecha: new Date().toLocaleDateString("es-AR"),
        },
      };
      const res = await fetch(`${SHEETDB_URL}?sheet=pagos`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
      });
      if (!res.ok) throw new Error("No se pudo registrar el pago. Intentá de nuevo.");
      setEnviado(true);
      onEnviar();
    } catch (e) {
      setErr(e.message);
    } finally {
      setEnviando(false);
    }
  };

  return (
    <div className="modal-bg" onClick={onClose}>
      <div className="modal" onClick={(e) => e.stopPropagation()}>
        {!enviado ? <>
          <h3>Realizar pago</h3>
          <p className="sub">Transferí al alias y completá los datos para registrar tu pago.</p>
          <div className="alias-box">
            <div className="alias-row"><span className="alias-key">Alias</span><span className="alias-val">{alias.alias}</span></div>
            <div className="alias-row"><span className="alias-key">Receptor</span><span className="alias-val w">{alias.receptor}</span></div>
            <div className="alias-row"><span className="alias-key">CUIL</span><span className="alias-val w">{alias.cuil}</span></div>
          </div>
          <div className="monto-total">{fmt(total)}</div>
          <p style={{ textAlign: "center", color: "var(--light)", fontSize: "0.78rem", marginBottom: "1.25rem" }}>Podés pagar parcialmente si lo necesitás.</p>
          <div className="field-group"><label>Monto a transferir</label><input className="inp" type="number" value={monto} onChange={(e) => setMonto(e.target.value)} /></div>
          <div className="field-group"><label>Tu nombre en la transferencia</label><input className="inp" value={nombre} onChange={(e) => setNombre(e.target.value)} placeholder="Ej: Juan Pérez" /></div>
          <div className="field-group"><label>Concepto</label>
            <select value={concepto} onChange={(e) => setConcepto(e.target.value)}>
              {detalle.map((d, i) => <option key={i} value={d.concepto}>{d.concepto}</option>)}
              <option value="Pago parcial">Pago parcial / general</option>
            </select>
          </div>
          {err && <p className="err">⚠ {err}</p>}
          <div className="modal-actions">
            <button className="btn btn-outline btn-sm" onClick={onClose}>Cancelar</button>
            <button className="btn btn-gold btn-sm" disabled={!ok || enviando} onClick={confirmar} style={{ opacity: (!ok || enviando) ? 0.5 : 1 }}>
              {enviando ? "Enviando..." : "Confirmar pago"}
            </button>
          </div>
        </> : <>
          <h3>¡Registrado!</h3>
          <p className="sub">Tu declaración fue enviada correctamente.</p>
          <div className="pendiente-box">
            <div className="big">⏳</div>
            <strong>Pendiente de aprobación</strong>
            <p>Facundo o Elio validarán la recepción del dinero. Una vez confirmado, tu estado se actualizará.</p>
          </div>
          <div className="modal-actions" style={{ marginTop: "1.25rem" }}><button className="btn btn-gold" onClick={onClose}>Cerrar</button></div>
        </>}
      </div>
    </div>
  );
}


/* ─── PORTAL ────────────────────────────────────────────────────── */
function Portal({ data, reload }) {
  const { insc, torneos, config, jugadores } = data;
  const precioBotella = num(config.precio_botella) || 2000;
  const alias = { alias: config.alias || ALIAS_INIT.alias, receptor: config.receptor || ALIAS_INIT.receptor, cuil: config.cuil || ALIAS_INIT.cuil };

  const [tab, setTab] = useState("cuenta");
  const [dni, setDni] = useState("");
  const [jugador, setJugador] = useState(null);
  const [err, setErr] = useState("");
  const [buscado, setBuscado] = useState(false);
  const [pagoModal, setPagoModal] = useState(false);
  const [rankSearch, setRankSearch] = useState("");
  const [rankCat, setRankCat] = useState("General");

  const buscar = () => {
    const j = getJugadorByDni(insc, dni.trim());
    setBuscado(true);
    if (j) { setJugador(j); setErr(""); }
    else { setJugador(null); setErr("No encontramos ningún jugador con ese DNI cargado todavía. Si recién informaste tu DNI a Facundo, puede tardar un poco en aparecer."); }
  };

  const { total, detalle } = jugador ? calcularDeuda(jugador.filas, torneos, precioBotella) : { total: 0, detalle: [] };
  const puede = total === 0;

  const categorias = getCategorias(insc);
  const catFiltro = rankCat === "General" ? null : rankCat;
  const ranking = buildRanking(insc, catFiltro);
  const rankFiltrado = rankSearch ? ranking.filter((r) => r.nombre.toLowerCase().includes(rankSearch.toLowerCase())) : ranking;
  const podio = ranking.slice(0, 3);
  const rankingGeneral = buildRanking(insc, null);

  const proximos = Object.values(torneos).filter((t) => t.estado !== "finalizado");
  const categoriasPorTorneo = {};
  data.categorias.forEach((c) => {
    if (!categoriasPorTorneo[c.torneo_id]) categoriasPorTorneo[c.torneo_id] = [];
    categoriasPorTorneo[c.torneo_id].push(c);
  });

  return (
    <div>
      <div className="portal-tabs">
        {[["cuenta", "Mi Cuenta"], ["ranking", "Ranking"], ["torneos", "Torneos"], ["reglamento", "Reglamento"]].map(([v, l]) =>
          <button key={v} className={`ptab ${tab === v ? "on" : ""}`} onClick={() => setTab(v)}>{l}</button>
        )}
      </div>
      <div className="portal">

        {tab === "cuenta" && <>
          {pagoModal && jugador && <ModalPago jugador={jugador} torneos={torneos} precioBotella={precioBotella} alias={alias} onClose={() => { setPagoModal(false); reload(); }} onEnviar={() => {}} />}
          <div className="portal-hero">
            <img src={LOGO_B64} alt="Circuito Pádel TRH" className="hero-logo" />
            <h1>Circuito Pádel <span>TRH</span></h1>
            <p>Termas de Río Hondo · Consultá tu estado y realizá pagos</p>
          </div>
          <div className="card">
            <span className="card-label">Ingresá tu DNI</span>
            <div className="input-row">
              <input className="inp" placeholder="Ej: 30123456" value={dni} onChange={(e) => { setDni(e.target.value); setBuscado(false); setJugador(null); setErr(""); }} onKeyDown={(e) => e.key === "Enter" && buscar()} maxLength={10} />
              <button className="btn btn-gold" onClick={buscar}>Consultar</button>
            </div>
            {buscado && err && <p className="err">⚠ {err}</p>}
          </div>

          {jugador && <div className="jug-card">
            <div className="jug-top">
              <div><div className="jug-name">{jugador.nombre}</div><div className="jug-dni">DNI {jugador.dni}</div></div>
              <span className={`badge ${puede ? "badge-g" : "badge-r"}`}>{puede ? "✓ Al día" : "✗ Con deuda"}</span>
            </div>

            {!puede && <div className="alert alert-r"><span className="alert-icon">⚠️</span><div><strong>No podés inscribirte al próximo torneo</strong><p>Debés saldar {fmt(total)} antes de reservar tu plaza.</p></div></div>}

            {detalle.length > 0 && <div className="section">
              <div className="section-title">Deuda pendiente</div>
              <div className="deuda-box">
                {detalle.map((d, i) => <div className="deuda-row" key={i}><span>{d.concepto}</span><span className="red">{fmt(d.monto)}</span></div>)}
                <div className="deuda-total-row"><span>Total adeudado</span><span className="red">{fmt(total)}</span></div>
              </div>
              <button className="btn btn-gold" style={{ width: "100%", marginTop: "1rem" }} onClick={() => setPagoModal(true)}>💳 Pagar ahora</button>
            </div>}

            <div className="section">
              <div className="section-title">Puntos acumulados</div>
              <div style={{ display: "flex", alignItems: "center", gap: "1rem", background: "var(--dark2)", borderRadius: "8px", padding: "1rem" }}>
                <div style={{ fontFamily: "'Barlow Condensed',sans-serif", fontSize: "3rem", fontWeight: 900, color: "var(--gold)", lineHeight: 1 }}>
                  {rankingGeneral.find((r) => r.nombre === jugador.nombre)?.puntos || 0}
                </div>
                <div>
                  <div style={{ color: "var(--white)", fontWeight: 600, fontSize: "0.9rem" }}>puntos totales</div>
                  <div style={{ color: "var(--light)", fontSize: "0.78rem", marginTop: "0.2rem" }}>
                    {(() => { const pos = rankingGeneral.findIndex((r) => r.nombre === jugador.nombre) + 1; return pos > 0 ? `Posición #${pos} en el ranking general` : "Todavía sin puntos registrados"; })()}
                  </div>
                </div>
              </div>
            </div>

            <div className="section">
              <div className="section-title">Historial de torneos</div>
              {jugador.filas.map((t, i) => {
                const cfg = torneos[t.torneo_id];
                return <div className="torn-item" key={i}>
                  <div className="torn-header">
                    <div><div className="torn-nombre">{cfg?.nombre || t.torneo_id}</div><div className="torn-sede">{cfg?.sede}</div></div>
                    {t.resultado && <span className="chip chip-gold">{t.resultado}{t.puntos ? ` · ${t.puntos} pts` : ""}</span>}
                  </div>
                  <div className="torn-fields">
                    <span className="torn-label">Pago:</span>
                    <span className={`chip ${t.pagado100 ? "chip-g" : t.pagado50 ? "chip-o" : "chip-r"}`}>{t.pagado100 ? "Completo" : t.pagado50 ? "50% pagado" : "Sin pago"}</span>
                    {t.metodoPago && <span className="chip chip-gr">{t.metodoPago}</span>}
                    {t.categoria && <span className="chip chip-b">{t.categoria}</span>}
                    {t.pareja && <><span className="torn-label" style={{ marginLeft: "0.3rem" }}>Pareja:</span><span style={{ color: "var(--off)", fontSize: "0.82rem" }}>{t.pareja}</span></>}
                    {t.botellasDeuda > 0 && <span className="chip chip-r">{t.botellasDeuda} bot. sin pagar</span>}
                  </div>
                </div>;
              })}
            </div>

            {puede && <div className="alert alert-g"><span className="alert-icon">🎾</span><div><strong>¡Estás al día!</strong><p>Podés inscribirte al próximo torneo. Contactá a la organización para reservar tu plaza.</p></div></div>}
          </div>}
        </>}

        {tab === "ranking" && <div style={{ paddingTop: "1.5rem" }}>
          <div className="proximos-title">Ranking 2026</div>
          <div className="pts-table" style={{ marginBottom: "1.25rem" }}>
            {Object.entries(PUNTOS).map(([k, v]) => <div className="pts-row" key={k}><span className="pts-label">🏆 {k}</span><span className="pts-val">{v} pts</span></div>)}
          </div>
          <div className="rank-cat-tabs">
            {["General", ...categorias].map((c) => <button key={c} className={`rank-cat-btn ${rankCat === c ? "on" : ""}`} onClick={() => setRankCat(c)}>{c}</button>)}
          </div>
          {podio.length >= 3 && <div className="ranking-podio">
            {[podio[1], podio[0], podio[2]].map((r, i) => {
              const pos = i === 0 ? 2 : i === 1 ? 1 : 3;
              return <div className={`podio-card p${pos}`} key={r.nombre}>
                <div className="podio-pos">{pos === 1 ? "🥇" : pos === 2 ? "🥈" : "🥉"}</div>
                <div className="podio-nombre">{r.nombre.split(" ")[0]}</div>
                <div className="podio-pts">{r.puntos} pts</div>
              </div>;
            })}
          </div>}
          <input className="ranking-search" placeholder="Buscar jugador..." value={rankSearch} onChange={(e) => setRankSearch(e.target.value)} />
          <div className="ranking-list">
            {rankFiltrado.length === 0 ? <div className="empty">Sin jugadores con puntos en esta categoría.</div>
              : rankFiltrado.map((r) => {
                const posReal = ranking.indexOf(r) + 1;
                return <div className={`rank-row ${rankSearch && r.nombre.toLowerCase().includes(rankSearch.toLowerCase()) ? "hl" : ""}`} key={r.nombre}>
                  <div className="rank-pos">{posReal}</div>
                  <div style={{ flex: 1 }}>
                    <div className="rank-nombre">{r.nombre}</div>
                    {r.detalle.length > 0 && <div className="rank-det">{r.detalle.map((d) => `${d.resultado} (${d.categoria})`).join(" · ")}</div>}
                  </div>
                  <div className="rank-pts">{r.puntos} pts</div>
                </div>;
              })
            }
          </div>
        </div>}

        {tab === "torneos" && <div style={{ paddingTop: "1.5rem" }}>
          <div className="proximos-title">Calendario 2026</div>
          <div style={{ background: "var(--dark)", border: "1px solid var(--border2)", borderRadius: "10px", padding: "1rem", marginBottom: "1.25rem", color: "var(--off)", fontSize: "0.85rem", lineHeight: 1.6 }}>
            🏆 6 Abiertos + Master Final · Ranking individual acumulado · Podés jugar con distintas parejas en cada torneo.
          </div>
          {Object.values(torneos).map((t) => (
            <div className="proximo-card" key={t.torneo_id}>
              <div className="proximo-top">
                <div>
                  <div className="proximo-nombre">{t.nombre}</div>
                  <div className="proximo-sede">📍 {t.sede}</div>
                  <div className="proximo-fecha">📅 {t.fecha}</div>
                </div>
                <div>
                  {t.estado !== "finalizado" ? <><div className="proximo-precio">{fmt(t.inscripcion)}</div><div className="proximo-precio-sub">por jugador</div></> : <span className="chip chip-gr">Finalizado</span>}
                </div>
              </div>
              {categoriasPorTorneo[t.torneo_id] && categoriasPorTorneo[t.torneo_id].length > 0 && <div className="cat-list">
                {categoriasPorTorneo[t.torneo_id].map((c, i) => {
                  const libre = c.cupoTotal - c.inscriptos;
                  const pct = c.cupoTotal ? (c.inscriptos / c.cupoTotal) * 100 : 0;
                  const agotado = c.cupoTotal > 0 && libre <= 0;
                  const casi = pct >= 80 && !agotado;
                  return <div className="cat-row" key={i}>
                    <span className="cat-name">{c.categoria_id}</span>
                    <div className="cat-cupo">
                      <div className="cupo-bar"><div className={`cupo-fill ${agotado ? "full" : casi ? "almost" : ""}`} style={{ width: `${Math.min(pct, 100)}%` }} /></div>
                      {agotado ? <span className="cupo-agotado">Sin cupos</span> : t.estado === "finalizado" ? <span className="cupo-text">Finalizado</span> : <span className="cupo-text">{libre} lugar{libre !== 1 ? "es" : ""}</span>}
                    </div>
                  </div>;
                })}
              </div>}
            </div>
          ))}
        </div>}

        {tab === "reglamento" && <div style={{ paddingTop: "1.5rem" }}>
          <div className="proximos-title">Reglamento</div>
          <div className="reg-intro"><p>📌 Leé las FAQs completas antes del inicio del torneo. Acá está explicado el formato, horarios, W.O., peloteo, descansos, criterios de desempate y reglamento general. Evitemos dudas durante la competencia 🎾</p></div>
          {REGLAMENTO.map((r, i) => (
            <div className="reg-card" key={i}>
              <div className="reg-titulo"><span>{r.icon}</span>{r.titulo}</div>
              <div className="reg-texto">{r.texto}</div>
            </div>
          ))}
        </div>}

      </div>
    </div>
  );
}


/* ─── ROOT ──────────────────────────────────────────────────────── */
export default function App() {
  const { loading, error, data, reload } = useSheetData();

  return (
    <div style={{ minHeight: "100vh", background: "var(--black)" }}>
      <style>{CSS}</style>
      <style>{`
        .loading-wrap{display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:60vh;gap:1rem;padding:2rem;text-align:center}
        .spinner{width:42px;height:42px;border:3px solid var(--border2);border-top-color:var(--gold);border-radius:50%;animation:spin 0.8s linear infinite}
        @keyframes spin{to{transform:rotate(360deg)}}
        .loading-wrap p{color:var(--light);font-size:0.9rem}
        .error-box{background:var(--red-dim);border:1px solid rgba(232,64,64,0.25);border-radius:10px;padding:1.5rem;max-width:480px}
        .error-box strong{color:var(--red);display:block;margin-bottom:0.5rem;font-family:'Barlow Condensed',sans-serif;text-transform:uppercase;letter-spacing:0.05em}
        .error-box p{color:var(--off);font-size:0.85rem;line-height:1.5}
      `}</style>
      <div className="top-nav">
        <div className="brand">
          <img src={LOGO_B64} alt="CP TRH" className="brand-logo" />
          <span className="brand-name">Circuito Pádel <span>TRH</span></span>
        </div>
      </div>

      {loading && <div className="loading-wrap"><div className="spinner" /><p>Cargando datos del Circuito Pádel TRH...</p></div>}

      {error && <div className="loading-wrap">
        <div className="error-box">
          <strong>⚠ No se pudieron cargar los datos</strong>
          <p>{error}</p>
          <p style={{ marginTop: "0.5rem" }}>Verificá que el Google Sheets esté compartido como "Cualquiera con el enlace" y que las hojas se llamen exactamente: jugadores, inscripciones, torneos, categorías, config, pagos.</p>
        </div>
        <button className="btn btn-gold" onClick={reload} style={{ marginTop: "1rem" }}>Reintentar</button>
      </div>}

      {!loading && !error && data && <Portal data={data} reload={reload} />}
    </div>
  );
}
